.darma-loader-darma-custom-281 {
  color: var(--loader-color, #7c3aed);
  display: inline-grid;
  width: 68px;
  aspect-ratio: 1;
  animation: darma-loader-darma-custom-281-l6-0 .5s linear infinite;
  background: 
   conic-gradient(from -34deg at 50% 99%,#0000, var(--loader-secondary-color, #c084fc) 2deg 65deg,#0000 68deg)
   -6% 0%/20% 27% repeat-x,
   conic-gradient(from 146deg at 50% 1%,#0000, var(--loader-secondary-color, #c084fc) 2deg 65deg,#0000 68deg)
   -5% 100%/20% 27% repeat-x;
}
.darma-loader-darma-custom-281:before {
  content:"";
  animation: inherit;
  animation-name: darma-loader-darma-custom-281-l6-1;
  margin: 12.5%;
  clip-path: polygon(100% 50%,78.19% 60.26%,88.3% 82.14%,65% 75.98%,58.68% 99.24%,44.79% 79.54%,25% 93.3%,27.02% 69.28%,3.02% 67.1%,20% 50%,3.02% 32.9%,27.02% 30.72%,25% 6.7%,44.79% 20.46%,58.68% 0.76%,65% 24.02%,88.3% 17.86%,78.19% 39.74%);
  background: var(--loader-color, #7c3aed);
}
@keyframes darma-loader-darma-custom-281-l6-0 {to{background-position:-31% 0%, 20% 100%}}
@keyframes darma-loader-darma-custom-281-l6-1 {to{rotate: -40deg}}

